class ChartData {
  ChartData({
      String? change, 
      List<ChartHistoryData>? history,}){
    _change = change;
    _history = history;
}

  ChartData.fromJson(dynamic json) {
    _change = json['change'];
    if (json['history'] != null) {
      _history = [];
      json['history'].forEach((v) {
        _history?.add(ChartHistoryData.fromJson(v));
      });
    }
  }
  String? _change;
  List<ChartHistoryData>? _history;
ChartData copyWith({  String? change,
  List<ChartHistoryData>? history,
}) => ChartData(  change: change ?? _change,
  history: history ?? _history,
);
  String? get change => _change;
  List<ChartHistoryData>? get history => _history;

  Map<String, dynamic> toJson() {
    final map = <String, dynamic>{};
    map['change'] = _change;
    if (_history != null) {
      map['history'] = _history?.map((v) => v.toJson()).toList();
    }
    return map;
  }

}

